# scripts/check_version_bump.py — compare changed YAML to git HEAD
import subprocess, yaml, sys
from pathlib import Path
from packaging.version import Version

def get_head_content(path: str) -> dict | None:
    result = subprocess.run(
        ["git", "show", f"HEAD:{path}"], capture_output=True, text=True
    )
    if result.returncode != 0:
        return None   # new file — any version is valid
    return yaml.safe_load(result.stdout)

failed = False
for path in Path("src/prompts").rglob("*.yaml"):
    head = get_head_content(str(path))
    current = yaml.safe_load(path.read_text())
    if head is None:
        print(f"OK   {path} (new file)")
        continue

    old_v = Version(head["version"])
    new_v = Version(current["version"])

    old_required = {k for k, v in head.get("variables", {}).items() if v.get("required")}
    new_required = {k for k, v in current.get("variables", {}).items() if v.get("required")}
    required_changed = old_required != new_required

    if required_changed and new_v.major == old_v.major:
        print(f"FAIL {path}: required variable change needs MAJOR bump "
              f"(got {old_v}→{new_v})")
        failed = True
    elif new_v < old_v:
        print(f"FAIL {path}: version went backwards ({old_v}→{new_v})")
        failed = True
    else:
        print(f"OK   {path}: {old_v}→{new_v}")

sys.exit(1 if failed else 0)

# scripts/run_prompt_evals.py — profile-based threshold
def get_profile_threshold(template: dict) -> float:
    surface = template.get("injection_surface", "low")
    has_user = template.get("contains_user_content", False)

    if surface == "high" or (has_user and surface == "medium"):
        return 0.95   # CRITICAL
    if has_user or surface == "medium":
        return 0.90   # HIGH
    # Check if customer-facing from deployment context tag
    if "customer-facing" in template.get("tags", []):
        return 0.85   # MEDIUM
    return 0.80       # LOW (internal tooling)

import hashlib, json
from pathlib import Path

CACHE_DIR = Path(".eval-cache")
CACHE_TTL_SECONDS = 86400   # 24 hours

def cache_key(template_id: str, eval_id: str, model: str, inputs: dict) -> str:
    payload = json.dumps({"tid": template_id, "eid": eval_id,
                           "model": model, "inputs": inputs}, sort_keys=True)
    return hashlib.sha256(payload.encode()).hexdigest()[:16]

def get_cached(key: str) -> dict | None:
    path = CACHE_DIR / f"{key}.json"
    if not path.exists():
        return None
    import time
    if time.time() - path.stat().st_mtime > CACHE_TTL_SECONDS:
        path.unlink()
        return None
    return json.loads(path.read_text())

def put_cache(key: str, result: dict) -> None:
    CACHE_DIR.mkdir(exist_ok=True)
    (CACHE_DIR / f"{key}.json").write_text(json.dumps(result))

# scripts/collect_gate_metrics.py — parse GitHub Actions runs for gate stats
from github import Github
import os, statistics

g = Github(os.environ["GH_TOKEN"])
repo = g.get_repo(os.environ["REPO"])

gate_runs = {"schema-lint": [], "prompt-lint": [], "version-check": [], "eval-suite": []}
cost_per_run = []

for workflow_run in repo.get_workflow_runs(branch="main", status="completed"):
    if "prompt-gates" not in workflow_run.name.lower():
        continue
    for job in workflow_run.get_jobs():
        name = job.name.lower().replace(" ", "-")
        if name in gate_runs:
            duration_s = (job.completed_at - job.started_at).total_seconds()
            gate_runs[name].append({
                "duration_s": duration_s,
                "conclusion": job.conclusion,
            })

for gate, runs in gate_runs.items():
    if not runs:
        continue
    pass_rate = sum(1 for r in runs if r["conclusion"] == "success") / len(runs)
    p95 = statistics.quantiles([r["duration_s"] for r in runs], n=20)[-1]
    print(f"{gate}: pass_rate={pass_rate:.1%} p95={p95:.0f}s n={len(runs)}")
